export type RegionSlug = 'moskva' | 'moskovskaya-oblast' | 'novosibirsk' | 'ekaterinburg' | 'kazan' | 'nizhniy-novgorod' | 'sankt-peterburg' | 'chelyabinsk' | 'omsk' | 'samara' | 'rostov-na-donu' | 'ufa' | 'krasnodar' | 'perm' | 'voronezh' | 'volgograd' | 'krasnoyarsk' | 'saratov' | 'tomsk'

export interface SchoolProgram {
  grades: string        // '1-4' | '5-9' | '10-11'
  level: string         // 'Начальная школа' | 'Основная' | 'Старшая'
  subjects: string[]    // ключевые предметы/направления
  description: string   // 1-2 предложения
}

export interface SchoolFAQ {
  question: string
  answer: string
}

export interface School {
  id: string
  slug: string
  name: string
  type: SchoolType
  region: RegionSlug
  city: string
  address: string
  phone: string
  website?: string
  email?: string
  description: string
  fullDescription: string
  grades: string
  license?: string
  founded?: number
  studentsCount?: number
  features: string[]
  metro?: string
  district?: string
  neighborhood?: string
  rating: number
  reviewCount: number
  priceFrom?: number
  priceTo?: number
  imageAlt: string
  lat?: number
  lon?: number
  languages?: string[]   // языки обучения, напр. ['english', 'german']
  boarding?: boolean     // есть пансион/интернат
  // New enrichment fields
  director?: string           // 'Иванова Анна Петровна'
  workHours?: string          // 'Пн-Пт: 8:00-19:00, Сб: 9:00-14:00'
  egeAvgScore?: number        // средний балл ЕГЭ (например 68.5)
  egeYear?: number            // год результатов ЕГЭ
  programs?: SchoolProgram[]  // программы по ступеням
  achievements?: string[]     // достижения последних лет
  faq?: SchoolFAQ[]           // FAQ для страницы школы
}

