export const profileSlugs: ProfileSlug[] = profileMetas.map(p => p.slug)

export function getProfileBySlug(slug: string): ProfileMeta | undefined {
  return profileMetas.find(p => p.slug === slug)
}

export function getSchoolsByProfile(profileSlug: ProfileSlug, region?: RegionSlug): School[] {
  const meta = getProfileBySlug(profileSlug)
  if (!meta) return []
  return schools.filter(s => {
    if (s.type !== 'profilnye') return false
    if (region && s.region !== region) return false
    const haystack = [s.name, s.description, s.fullDescription ?? '', ...s.features].join(' ').toLowerCase()
    return meta.keywords.some(kw => haystack.includes(kw.toLowerCase()))
  })
}

